SELECT coordinate
FROM stations_coordinates
WHERE station_id = 0;

SELECT COUNT(*) 
FROM datasets_metadata 
WHERE metadata = '{"key": "value"}';

SELECT division_id, COUNT(station_id) AS station_count
FROM stations_divisions
GROUP BY division_id;

SELECT COUNT(station_id) AS station_count
FROM stations
WHERE division = (SELECT division FROM divisions WHERE division_id = 1);

SELECT division_name
FROM divisions
ORDER BY division_name ASC;

SELECT COUNT(*) AS number_of_users_with_role_1
FROM users_roles
WHERE role = '1';
